// src/components/appointments/AppointmentCalendar.js
import React, { useState, useEffect, useCallback } from 'react';
import { useToast } from '../../context/ToastContext';
import appointmentService from '../../services/appointmentService';
import LoadingSpinner from '../common/LoadingSpinner';
import './AppointmentCalendar.css';

const AppointmentCalendar = () => {
    const { showSuccess, showError } = useToast();
    const [appointments, setAppointments] = useState([]);
    const [loading, setLoading] = useState(true);
    const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);
    const [showForm, setShowForm] = useState(false);
    const [formData, setFormData] = useState({
        title: '',
        description: '',
        appointment_date: new Date().toISOString().split('T')[0],
        appointment_time: '09:00',
        duration: 30,
        doctor_id: ''
    });

    // Wrap fetchAppointments in useCallback
    const fetchAppointments = useCallback(async () => {
        try {
            setLoading(true);
            const data = await appointmentService.getAppointments();
            setAppointments(data);
        } catch (error) {
            showError('Failed to load appointments');
        } finally {
            setLoading(false);
        }
    }, [showError]);

    useEffect(() => {
        fetchAppointments();
    }, [selectedDate, fetchAppointments]);

    const handleInputChange = (e) => {
        setFormData({
            ...formData,
            [e.target.name]: e.target.value
        });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            await appointmentService.createAppointment(formData);
            showSuccess('Appointment scheduled successfully');
            setShowForm(false);
            fetchAppointments();
        } catch (error) {
            showError(error.message);
        }
    };

    const handleCancel = async (id) => {
        if (window.confirm('Are you sure you want to cancel this appointment?')) {
            try {
                await appointmentService.cancelAppointment(id);
                showSuccess('Appointment cancelled');
                fetchAppointments();
            } catch (error) {
                showError('Failed to cancel appointment');
            }
        }
    };

    const getStatusClass = (status) => {
        switch(status) {
            case 'scheduled': return 'status-scheduled';
            case 'completed': return 'status-completed';
            case 'cancelled': return 'status-cancelled';
            default: return '';
        }
    };

    if (loading) return <LoadingSpinner text="Loading appointments..." />;

    return (
        <div className="appointment-calendar">
            <div className="calendar-header">
                <h2>Appointment Calendar</h2>
                <button 
                    className="btn btn-primary"
                    onClick={() => setShowForm(!showForm)}
                >
                    {showForm ? 'Cancel' : '+ New Appointment'}
                </button>
            </div>

            <div className="date-selector">
                <input
                    type="date"
                    value={selectedDate}
                    onChange={(e) => setSelectedDate(e.target.value)}
                    className="date-input"
                />
            </div>

            {showForm && (
                <div className="appointment-form">
                    <h3>Schedule New Appointment</h3>
                    <form onSubmit={handleSubmit}>
                        <div className="form-group">
                            <label>Title</label>
                            <input
                                type="text"
                                name="title"
                                value={formData.title}
                                onChange={handleInputChange}
                                required
                            />
                        </div>

                        <div className="form-group">
                            <label>Description</label>
                            <textarea
                                name="description"
                                value={formData.description}
                                onChange={handleInputChange}
                                rows="3"
                            />
                        </div>

                        <div className="form-row">
                            <div className="form-group">
                                <label>Date</label>
                                <input
                                    type="date"
                                    name="appointment_date"
                                    value={formData.appointment_date}
                                    onChange={handleInputChange}
                                    required
                                />
                            </div>

                            <div className="form-group">
                                <label>Time</label>
                                <input
                                    type="time"
                                    name="appointment_time"
                                    value={formData.appointment_time}
                                    onChange={handleInputChange}
                                    required
                                />
                            </div>

                            <div className="form-group">
                                <label>Duration (min)</label>
                                <select
                                    name="duration"
                                    value={formData.duration}
                                    onChange={handleInputChange}
                                >
                                    <option value="15">15 min</option>
                                    <option value="30">30 min</option>
                                    <option value="45">45 min</option>
                                    <option value="60">60 min</option>
                                </select>
                            </div>
                        </div>

                        <button type="submit" className="btn btn-success">
                            Schedule Appointment
                        </button>
                    </form>
                </div>
            )}

            <div className="appointments-list">
                <h3>Appointments for {new Date(selectedDate).toLocaleDateString()}</h3>
                {appointments.filter(apt => apt.appointment_date === selectedDate).length === 0 ? (
                    <p className="no-appointments">No appointments scheduled for this date</p>
                ) : (
                    appointments
                        .filter(apt => apt.appointment_date === selectedDate)
                        .sort((a, b) => a.appointment_time.localeCompare(b.appointment_time))
                        .map(appointment => (
                            <div key={appointment.id} className={`appointment-card ${getStatusClass(appointment.status)}`}>
                                <div className="appointment-time">
                                    {appointment.appointment_time}
                                </div>
                                <div className="appointment-details">
                                    <h4>{appointment.title}</h4>
                                    <p>{appointment.description}</p>
                                    <p className="appointment-meta">
                                        Duration: {appointment.duration} min | 
                                        Status: {appointment.status}
                                    </p>
                                </div>
                                {appointment.status === 'scheduled' && (
                                    <button 
                                        className="btn-cancel"
                                        onClick={() => handleCancel(appointment.id)}
                                    >
                                        Cancel
                                    </button>
                                )}
                            </div>
                        ))
                )}
            </div>
        </div>
    );
};

export default AppointmentCalendar;
